onClick:
{{
  (async () => {
    try {
      const loginRows = await loginUser.run();
      const user = loginRows?.[0] || loginUser.data?.[0];

      if (!user) {
        showAlert("Wrong username or password", "error");
        return;
      }

      await storeValue("userId", user.user_id);
      await storeValue("username", user.username);
      await storeValue("companyId", user.company_id);
      await storeValue("companyName", user.company_name);
      await storeValue("roleId", user.role_id);
      await storeValue("roleCode", user.role_code);
      await storeValue("roleName", user.role_name);

      const warehouseRows = await warehouseId.run();
      const warehouse = warehouseRows?.[0] || warehouseId.data?.[0] || {};

      await storeValue("warehouseId", warehouse.warehouseId || warehouse.id || null);
      await storeValue("warehouseCode", warehouse.warehouseCode || warehouse.code || "");
      await storeValue("warehouseName", warehouse.warehouseName || warehouse.name || "");

      const accessRows = await GetCurrentUserAccess.run();
      const access = accessRows || GetCurrentUserAccess.data || [];

      await storeValue("currentUserAccess", access);
      await storeValue("roleCode", access?.[0]?.roleCode || user.role_code || "");
      await storeValue("roleName", access?.[0]?.roleName || user.role_name || "");
      await storeValue(
        "permissions",
        [...new Set(access.map(x => x.permissionCode).filter(Boolean))]
      );

      if (!warehouse.warehouseId && !warehouse.id) {
        showAlert("No warehouse found for this company.", "warning");
      }

      showModal("Warehouse");
    } catch (error) {
      showAlert("Login failed: " + error.message, "error");
      console.log(error);
    }
  })()
}}
